    else
      c = std::bit_cast<float>(raw2);
    if (inst.inst_.neg & 1)
      a = -a;
    if (inst.inst_.neg & 2)
      b = -b;
    if (inst.inst_.neg & 4)
      c = -c;
    float result = a * b + c;
    if (inst.inst_.clamp)
      result = std::clamp(result, 0.0f, 1.0f);
    inst.vdst.write_lane(wf, lane, std::bit_cast<uint32_t>(result));
