      continue;
    float sv0 = util::f16_to_f32(static_cast<uint16_t>(inst.src0.read_lane(wf, lane)));
    int32_t sv1_i = static_cast<int32_t>(
        static_cast<int16_t>(static_cast<uint16_t>(inst.vsrc1.read_lane(wf, lane))));
